          borderRadius: 6,
          cursor: "pointer",
        }}
      >
        Parsha Deck
      </button>

      {/* Tzedakah Fund Display */}
      <div
        style={{
          position: "absolute",
          top: "69.5%",
          left: "26.5%",
          transformOrigin: "left center",
          transform: "translate(-50%, -50%) rotate(48deg)",
          backgroundColor: "#f7e600",
          color: "#333",
          border: "2px solid #bfa800",
          borderRadius: 10,
          padding: "8px 18px",
          fontWeight: "bold",
          fontSize: 16,
          boxShadow: "0 2px 8px #aaa",
          zIndex: 2,
        }}
      >
        Tzedakah: ${tzedakahAmount || 0}
      </div>

      {/* Zchut Fund Display */}
      <div
        style={{
          position: "absolute",
          top: "58%", // another 1/32 inch down
          left: "39.5%", // another 1/32 inch right
          transformOrigin: "left center",
          transform: "translate(-50%, -50%) rotate(48deg)",
          backgroundColor: "#f7e600",
          color: "#333",
          border: "2px solid #bfa800",
          borderRadius: 10,
          padding: "8px 18px",
          fontWeight: "bold",
          fontSize: 16,
          boxShadow: "0 2px 8px #aaa",
          zIndex: 2,
        }}
      >
        Zchut: {zchutFundAmount || 0}
      </div>

      {/* Shuffle Button */}
      <div
        style={{
          position: "absolute",
          top: "70%",
          left: "73%",
          display: "flex",
          flexDirection: "row",
          gap: "18px",
          transformOrigin: "right center",
          transform: "translate(-50%, -50%) rotate(-46deg)",
        }}
      >
        <button
          onClick={onShuffleParsha}
          style={{
            padding: "4px 10px",
            fontSize: 12,
            backgroundColor: "#ff9800",
            color: "#fff",
            border: "2px solid #000",
            borderRadius: 8,
            cursor: "pointer",
            boxShadow: "0 2px 8px #aaa",
          }}
        >
          Shuffle
        </button>
        <button
          onClick={onReturnParsha}
          style={{
            padding: "4px 10px",
            fontSize: 12,
            backgroundColor: "#007bff",
            color: "#fff",
            border: "2px solid #000",
            borderRadius: 8,
            cursor: "pointer",
            boxShadow: "0 2px 8px #aaa",
          }}
        >
          Return
        </button>
      </div>
    </>
  );
}

// Export card data for use elsewhere
export { bereshitCard, harHaBayitCard, mazalCards, tzadikCard, parshaCard };
